import{_ as d,o as a,c as s,a2 as o}from"./chunks/framework.C90q7Ucc.js";const m=JSON.parse('{"title":"JSON Schema 与本地数据契约","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/json-schemas.md","filePath":"architecture/json-schemas.md","lastUpdated":1780678956000}'),t={name:"architecture/json-schemas.md"};function c(i,e,n,h,r,l){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="json-schema-与本地数据契约" tabindex="-1">JSON Schema 与本地数据契约 <a class="header-anchor" href="#json-schema-与本地数据契约" aria-label="Permalink to &quot;JSON Schema 与本地数据契约&quot;">​</a></h1><p>CodeLark 为 <code>~/.codelark</code> 下的本地数据文件发布 JSON Schema。入口文件在仓库根目录的 <code>schemas/manifest.json</code>。</p><p>这些 schema 主要服务三件事，不负责自动升级：</p><ul><li>在 bridge 读取前校验用户手动编辑过的本地文件。</li><li>给 <code>doctor</code> 或显式修复脚本提供机器可读的文件清单。</li><li>把禁止回流的旧字段写成可测试的契约。</li></ul><p>如果数据结构需要调整，运行时代码或一次性脚本必须显式处理；JSON Schema 只描述“当前应该长什么样”。项目不维护历史 schema 兼容面，所以当前发布的 schema 版本都从 <code>1</code> 开始。</p><h2 id="文件清单" tabindex="-1">文件清单 <a class="header-anchor" href="#文件清单" aria-label="Permalink to &quot;文件清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>运行时文件</th><th>Schema</th><th>说明</th></tr></thead><tbody><tr><td><code>config.json</code></td><td><code>schemas/config.v1.schema.json</code></td><td>结构化配置，版本字段是 <code>schemaVersion: 1</code>。</td></tr><tr><td><code>data/sessions.json</code></td><td><code>schemas/data/sessions.v1.schema.json</code></td><td>以 Bridge session id 为 key 的 map；<code>runtime.codex.threadId</code> 保存在这里。</td></tr><tr><td><code>data/channel-chats.json</code></td><td><code>schemas/data/channel-chats.v1.schema.json</code></td><td>以 ChannelChat id 为 key 的 map；使用 <code>bridgeSessionId</code> 指向 session，禁止保存 thread 身份和旧 binding 运行时字段。</td></tr><tr><td><code>data/channel-default-targets.json</code></td><td><code>schemas/data/channel-default-targets.v1.schema.json</code></td><td>以 channel instance id 为 key 的默认目标 map；使用 <code>bridgeSessionId</code>，启动时会丢弃缺少它的旧记录。</td></tr><tr><td><code>data/messages/*.json</code></td><td><code>schemas/data/messages.v1.schema.json</code></td><td>单个 BridgeSession 的消息数组。</td></tr><tr><td><code>data/permissions.json</code></td><td><code>schemas/data/permissions.v1.schema.json</code></td><td>权限请求链接。</td></tr><tr><td><code>data/offsets.json</code></td><td><code>schemas/data/string-map.v1.schema.json</code></td><td>通道消费偏移 map。</td></tr><tr><td><code>data/dedup.json</code></td><td><code>schemas/data/number-map.v1.schema.json</code></td><td>去重时间戳 map。</td></tr><tr><td><code>data/audit.jsonl</code></td><td><code>schemas/data/audit.v1.schema.json</code></td><td>审计记录，当前新记录按 JSONL 追加；schema 描述单条记录形状和旧 <code>audit.json</code> 数组形状。</td></tr></tbody></table><h2 id="版本策略" tabindex="-1">版本策略 <a class="header-anchor" href="#版本策略" aria-label="Permalink to &quot;版本策略&quot;">​</a></h2><p>JSON Schema 本身不执行迁移。<code>schemas/manifest.json</code> 只声明当前文件清单、当前 schema 路径和缺失文件策略：</p><ol><li>读取 <code>schemas/manifest.json</code>。</li><li>将每个 <code>files[].path</code> 解析到 <code>~/.codelark</code> 下。</li><li>如果文件不存在，按 <code>missingFile</code> 策略处理。</li><li>用当前 schema 校验当前文档。</li></ol><p><code>schemaVersion</code> 是当前配置文件格式的断言，不是自动升级开关。破坏性调整发生时，如果项目决定不兼容旧格式，就直接更新 v1 schema 和代码。</p><h2 id="thread-身份迁移" tabindex="-1">Thread 身份迁移 <a class="header-anchor" href="#thread-身份迁移" aria-label="Permalink to &quot;Thread 身份迁移&quot;">​</a></h2><p>当前启动迁移主要修复 thread 身份重构。这是显式 TypeScript 代码，不是 schema 自动升级能力。</p><p>迁移前，旧数据里可能出现多种 thread 字段：</p><ul><li><code>sdk_session_id</code></li><li><code>sdkSessionId</code></li><li><code>desktop_thread_id</code></li><li><code>desktopThreadId</code></li><li><code>thread_origin</code></li><li><code>threadOrigin</code></li><li><code>thread_id</code></li><li><code>threadId</code></li><li>旧 binding 上的 <code>codex_thread_id</code></li><li>旧 binding 上的 <code>codexThreadId</code></li></ul><p>迁移后的目标只有一个：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BridgeSession.runtime.codex.threadId</span></span></code></pre></div><p>具体规则：</p><ul><li>session 上的 <code>sdk_session_id</code>、<code>desktop_thread_id</code>、<code>thread_id</code> 会在 session 没有 <code>runtime.codex.threadId</code> 时折叠进去。</li><li>旧 binding 到 ChannelChat 的迁移不在启动路径执行；显式脚本只保留 <code>active: true</code> 的旧记录，并把 <code>workingDirectory</code>、<code>model</code>、<code>mode</code>、<code>chatDisplayName</code> 迁到对应 session 的空字段，成功后删除旧 <code>data/bindings.json</code>。</li><li>旧 <code>data/ui-session-meta.json</code> 里的名称会合并到 <code>sessions.json.name</code>；只有本地 Codex thread 名称而没有 BridgeSession 时不会再创建新 BridgeSession，然后删除 <code>ui-session-meta.json</code>。</li><li>旧 <code>data/channel-default-targets.json</code> 会从 target selector 字符串改写成 <code>bridgeSessionId</code>。如果 selector 指向本地 Codex thread，会先 materialize 成 BridgeSession，再删除旧 selector 字段。</li></ul><h2 id="身份规则" tabindex="-1">身份规则 <a class="header-anchor" href="#身份规则" aria-label="Permalink to &quot;身份规则&quot;">​</a></h2><p><code>BridgeSession.runtime.codex.threadId</code> 是唯一持久化的 Codex thread 身份字段，必须保存在：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data/sessions.json</span></span></code></pre></div><p><code>data/channel-chats.json</code> 只能通过 <code>bridgeSessionId</code> 指向 session。它不应保存任何 Codex thread 身份，因为 ChannelChat 的职责是“IM chat -&gt; BridgeSession”，不是“IM chat -&gt; Codex thread”。</p><p>Schema 会拒绝这些已删除身份字段：</p><ul><li><code>sdk_session_id</code> / <code>sdkSessionId</code></li><li><code>desktop_thread_id</code> / <code>desktopThreadId</code></li><li><code>thread_origin</code> / <code>threadOrigin</code></li><li><code>thread_id</code> / <code>threadId</code></li><li>ChannelChat 上的 <code>codex_thread_id</code> / <code>codexThreadId</code></li></ul><h2 id="与架构链路的关系" tabindex="-1">与架构链路的关系 <a class="header-anchor" href="#与架构链路的关系" aria-label="Permalink to &quot;与架构链路的关系&quot;">​</a></h2><p>Schema 约束的是这条链路：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Codex thread id</span></span>
<span class="line"><span>  -&gt; data/sessions.json 中的 BridgeSession.runtime.codex.threadId</span></span>
<span class="line"><span>  -&gt; data/channel-chats.json 中的 ChannelChat.bridgeSessionId</span></span>
<span class="line"><span>  -&gt; channelType + chatId 对应的 IM chat</span></span></code></pre></div><p>如果 schema 允许 ChannelChat 保存 thread id，这条链路就会出现两个 thread 身份来源，history、mirror、reuse 和 <code>/t</code> 切换都会变得不一致。因此 schema 层必须把 thread 身份固定在 session 上。</p>`,29)])])}const u=d(t,[["render",c]]);export{m as __pageData,u as default};
